// src/components/Hero.js
import React from "react";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

function Hero() {
  const settings = {
    dots: true,
    infinite: true,
    speed: 600,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 3000,
  };

  const slides = [
    {
      text: "Limited Time Offer 30% Off",
      heading: "Experience Pure Sound - Your Perfect Headphones Awaits!",
      img: "https://via.placeholder.com/400x300?text=Headphones",
    },
    {
      text: "Exclusive Launch Deal 20% Off",
      heading: "Smartphones with Next-Gen Technology!",
      img: "https://via.placeholder.com/400x300?text=Smartphone",
    },
    {
      text: "Special Discount 40% Off",
      heading: "Upgrade Your Style with Premium Sneakers!",
      img: "https://via.placeholder.com/400x300?text=Sneakers",
    },
  ];

  return (
    <section className="hero">
      <Slider {...settings}>
        {slides.map((slide, index) => (
          <div key={index} className="hero-slide">
            <div className="hero-content">
              {/* Left: Text */}
              <div className="hero-text">
                <p>{slide.text}</p>
                <h1>{slide.heading}</h1>
                <div className="hero-buttons">
                  <button className="buy-btn">Buy now</button>
                  <button className="find-btn">Find more →</button>
                </div>
              </div>

              {/* Right: Image box */}
              <div className="hero-image">
                <img src={slide.img} alt={'Slide ${index + 1}'} />
              </div>
            </div>
          </div>
        ))}
      </Slider>
    </section>
  );
}

export default Hero;
